UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Appel, Japanse peer, Peer, Kweepeer, Mispel, Overige pitvruchten", "locatie": "Onbedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "0.6 L/ha", "maxToepassingen": 1, "veiligheidstermijn": "7 dagen", "opmerkingen": ["Geclaimde organismen: vruchtbladroller (Adoxophyes orana), bruinbandbladroller (Argyrotaenia ljungiana), bladrollers (Archips spp.), fruitmot (Cydia pomonella), kleine wintervlinder (Operophtera brumata), bladrollers (Pandemis spp.)\n\nToepassingsvoorwaarde: Maximaal 1 keer per 2 jaar toepassen\n\nDosering 0.05% (50 ml/100 L)\n\nVerlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgewe-ken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen. \n\n", {"sentenceNL": "Om het grondwater te beschermen geldt er voor deze toepassing een restrictie in grondwaterbeschermingsgebieden in de periode 01/jan. tot 31/dec.. De betreffende restrictiezin op het WG luidt: Om het grondwater te beschermen mag dit middel niet worden gebruikt in grondwaterbeschermingsgebieden. Om het grondwater te beschermen mag dit middel in de onbedekte teelt van pitvruchten, pruim en wijndruif op zijn vroegst in het 2e kalenderjaar na de laatste toepassing op hetzelfde perceel worden toegepast, waarbij in de tussenliggende periode geen andere middelen op basis van cyantraniliprole mogen worden toegepast.", "sentenceEN": "Om het grondwater te beschermen geldt er voor deze toepassing een restrictie in grondwaterbeschermingsgebieden in de periode 01/jan. tot 31/dec.. De betreffende restrictiezin op het WG luidt: Om het grondwater te beschermen mag dit middel niet worden gebruikt in grondwaterbeschermingsgebieden. Om het grondwater te beschermen mag dit middel in de onbedekte teelt van pitvruchten, pruim en wijndruif op zijn vroegst in het 2e kalenderjaar na de laatste toepassing op hetzel