UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Pootaardappel, Consumptieaardappel, Zetmeelaardappel", "doelorganisme": "Nerfamarant, Papegaaienkruid, Zandraket, Spiesmelde, Veerdelig tandzaad, Herderstasje, Kleine veldkers, Veldkers, Kluwen hoornbloem, Melganzenvoet, Stippelganzenvoet, Zeegroene ganzenvoet, Gele ganzenbloem, Kleine varkenskers, Grote varkenskers, Kroontjeskruid, Gewone steenraket, Gewone duivenkervel, Bleekgele hennepnetel, Harig knopkruid, Kaal knopkruid, Kleine ooievaarsbek, Hoenderbeet, Echte kamille, Reukloze kamille, Schijfkamille, Tuinbingelkruid, Akkervergeet-mij-nietje, Varkensgras, Zwaluwtong, Waterpeper, Knopige duizendknoop, Perzikkruid, Viltige duizendknoop, Akkerboterbloem, Blaartrekkende boterbloem, Gewone melkdistel, Gewone spurrie, Vogelpootklaver, Akkerereprijs, Klimopereprijs, Vierzaadwikke, Duist, Glad vingergras, Harig vingergras, Hanenpoot", "locatie": "Onbedekt", "toepassingsmethode": "Voor opkomst ", "dosering": "5 L/ha", "maxToepassingen": 1, "opmerkingen": ["Verlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen\n\nIn de teelt van aardappelen, het middel toepassen in 200 tot 400 liter water per ha. \n\nOm in het water levende organismen en niet tot de doelsoorten behorende insecten/geleedpotigen te beschermen is toepassing in de teelt van aardappelen uitsluitend toegestaan indien op het gehele perceel gebruik wordt gemaakt van een techniek uit tenminste de klasse DRT95 in combinatie met een teeltvrije zone van tenminste 175 centimeter gemeten vanaf het midden van de laatste gewasrij of de laatste plant in de rij tot aan de insteek van de sloot, of een techniek uit tenminste de klasse DRT97.5 in combinatie met een teeltvrije zone van tenminste 150 centimeter gemeten vanaf het midden van de laatste gewasrij of de laatste plant in de rij tot aan de insteek van de sloot.\n\nOm in het water levende organismen en niet tot de doelsoorten behorende insecten/geleedpotigen te beschermen is toepassing in de teelt van wintertarwe, wintergerst, triticale en droog te oogsten erwten uitsluitend toegestaan indien op het gehele perceel gebruik wordt gemaakt van een techniek uit tenminste de klasse DRT95 in combinatie met een teeltvrije zone van tenminste 150 centimeter gemeten vanaf het midden van de laatste gewasrij of de laatste plant in de rij tot aan de insteek van de sloot, of een techniek uit tenminste de klasse DRT97.5 in combinatie met een teeltvrije zone van tenminste 100 centimeter gemeten vanaf het midden van de laatste gewasrij of de laatste plant in de rij tot aan de insteek van de sloot..\n\n\nLet op: Als op een aangrenzend perceel bloeiende tulpen staan, kunnen bij contact met de werkzame stof de bloemstengels knikken (kiepers). Dit heeft geen invloed op opbrengst en nateelt.\n\nVolggewassen\nLet op: Na een toepassing van het product in het voorjaar, kunnen geen bonen als volggewas worden geteeld. \n\nVervanggewassen\nLet op: Bij herinzaai na het mislukken van de teelt kunnen mais, zomergranen, aardappels, erwten en zonnebloem als vervanggewas-sen worden geteeld. \n"], "bbchVan": "07", "bbchTot": "09", "seizoenVan": 3, "seizoenTot": 4, "spuitvolumeMin": 200, "spuitvolumeMax": 400, "maxDoseringPerSeizoen": "5 L/ha"}, {"gewas": "Gele erwt, Grauwe erwt, Groene erwt, Kapucijner, Kikkererwt, Linze, Rozijnerwt, Schokker, Suikererwt", "doelorganisme": "Nerfamarant, Papegaaienkruid, Zandraket, Spiesmelde, Veerdelig tandzaad, Herderstasje, Kleine veldkers, Veldkers, Kluwen hoornbloem, Melganzenvoet, Stippelganzenvoet, Zeegroene ganzenvoet, Gele ganzenbloem, Kleine varkenskers, Grote varkenskers, Kroontjeskruid, Gewone steenraket, Gewone duivenkervel, Bleekgele hennepnetel, Harig knopkruid, Kaal knopkruid, Kleine ooievaarsbek, Hoenderbeet, Echte kamille, Reukloze kamille, Schijfkamille, Tuinbingelkruid, Akkervergeet-mij-nietje, Varkensgras, Zwaluwtong, Waterpeper, Knopige duizendknoop, Perzikkruid, Viltige duizendknoop, Akkerboterbloem, Blaartrekkende boterbloem, Gewone melkdistel, Gewone spurrie, Vogelpootklaver, Akkerereprijs, Klimopereprijs, Vierzaadwikke, Duist, Glad vingergras, Harig vingergras, Hanenpoot", "locatie": "Onbedekt", "toepassingsmethode": "Voor opkomst ", "dosering": "5 L/ha", "maxToepassingen": 1, "opmerkingen": ["Verlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. \n\nIn de teelt van droog te oogsten erweten, het middel toepassen in 200 tot 400 liter water per ha. \n\nOm in het water levende organismen en niet tot de doelsoorten behorende insecten/geleedpotigen te beschermen is toepassing in de teelt van aardappelen uitsluitend toegestaan indien op het gehele perceel gebruik wordt gemaakt van een techniek uit tenminste de klasse DRT95 in combinatie met een teeltvrije zone van tenminste 175 centimeter gemeten vanaf het midden van de laatste gewasrij of de laatste plant in de rij tot aan de insteek van de sloot, of een techniek uit tenminste de klasse DRT97.5 in combinatie met een teeltvrije zone van tenminste 150 centimeter gemeten vanaf het midden van de laatste gewasrij of de laatste plant in de rij tot aan de insteek van de sloot.\n\nOm in het water levende organismen en niet tot de doelsoorten behorende insecten/geleedpotigen te beschermen is toepassing in de teelt van wintertarwe, wintergerst, triticale en droog te oogsten erwten uitsluitend toegestaan indien op het gehele perceel gebruik wordt gemaakt van een techniek uit tenminste de klasse DRT95 in combinatie met een teeltvrije zone van tenminste 150 centimeter gemeten vanaf het midden van de laatste gewasrij of de laatste plant in de rij tot aan de insteek van de sloot, of een techniek uit tenminste de klasse DRT97.5 in combinatie met een teeltvrije zone van tenminste 100 centimeter gemeten vanaf het midden van de laatste gewasrij of de laatste plant in de rij tot aan de insteek van de sloot..\n\nLet op: Als op een aangrenzend perceel bloeiende tulpen staan, kunnen bij contact met de werkzame stof de bloemstengels knikken (kiepers). Dit heeft geen invloed op opbrengst en nateelt.\n\nVolggewassen\nLet op: Na een toepassing van het product in het voorjaar, kunnen geen bonen als volggewas worden geteeld. \n\nVervanggewassen\nLet op: Bij herinzaai na het mislukken van de teelt kunnen mais, zomergranen, aardappels, erwten en zonnebloem als vervanggewas-sen worden geteeld. \n"], "bbchVan": "01", "bbchTot": "09", "seizoenVan": 3, "seizoenTot": 3, "spuitvolumeMin": 200, "spuitvolumeMax": 400, "maxDoseringPerSeizoen": "5 L/ha"}]'::jsonb, last_synced_at = NOW() WHERE toelatingsnummer = '16751';
